export type TypeGenCommentStyle = '//' | '#';

const AUTOGENERATED_BANNER_LINES = [
  'đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘',
  'đź›‘ THIS IS AN AUTOGENERATED FILE - DO NOT EDIT DIRECTLY đź›‘',
  'đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘ đź›‘',
];

export function getAutogeneratedBanner(commentStyle: TypeGenCommentStyle): string {
  const body = AUTOGENERATED_BANNER_LINES.map((line) => `${commentStyle} ${line}`).join('\n');
  return commentStyle === '//' ? `\n${body}` : body;
}
